const b = $input.first().json.body || $input.first().json || {};
// Truncar ETP para evitar estouro de tokens e rate limits (Anthropic 30k tokens/min)
const etpTruncado = (b.etp_content || '').substring(0, 15000);
return [{ json: {
  respostas_usuario: b.content || '',
  etp: etpTruncado,
  pesquisa_precos: b.pesquisa_precos_texto || '',
  matriz_risco: b.matriz_riscos || '',
  object_nature: b.object_nature || 'Aquisição de Bens',
  process_id: b.process_id || 'N/A'
}}];

const raw = $input.first().json?.output || '{}';
let dados = {};
try {
  const clean = raw.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  dados = JSON.parse(clean);
} catch(e) {
  dados = { objeto: 'Não identificado', itens: [], tem_pesquisa: false };
}
return [{
  json: {
    dados_precos: JSON.stringify(dados, null, 2),
    respostas_usuario: $('Normalizar_Dados').first().json.respostas_usuario,
    etp: $('Normalizar_Dados').first().json.etp,
    matriz_risco: $('Normalizar_Dados').first().json.matriz_risco,
    object_nature: $('Normalizar_Dados').first().json.object_nature,
    process_id: $('Normalizar_Dados').first().json.process_id
  }
}];

const outputRaw = $input.first().json?.output || '{}';
let variables = {};

try {
  if (typeof outputRaw === 'object' && outputRaw !== null) {
    variables = outputRaw.action_input || outputRaw;
  } else {
    let cleanJson = outputRaw.replace(/```json/g, '').replace(/```/g, '').trim();
    try {
      variables = JSON.parse(cleanJson);
    } catch (e) {
      const match = cleanJson.match(/\{.*\}/s);
      if (match) {
        try { variables = JSON.parse(match[0]); } catch (e2) { }
      }
    }
    if (variables.action === 'Final Answer' && variables.action_input) {
      variables = variables.action_input;
    }
  }
} catch (e) { }

// Manter os itens da pesquisa
let itens = [];
try {
  const dpRaw = $('Parser_Dados_Precos').first().json.dados_precos;
  const dp = typeof dpRaw === 'string' ? JSON.parse(dpRaw) : dpRaw;
  itens = dp.itens || [];
} catch(e) { }

// Gerar tabela markdown de itens formatada
let tabela_itens = '\n| Item |                 Descrição                  |  CATMAT  | Unid | Qtd. | Val. Unit. | Val. Total |\n|------|--------------------------------------------|----------|------|------|------------|------------|\n';
if (itens.length > 0) {
  itens.forEach(i => {
    const desc = (i.especificacao || '').padEnd(42, ' ').substring(0, 42);
    const catmat = (i.catmat || '').padEnd(8, ' ');
    const unid = (i.unidade || '').padEnd(4, ' ');
    const qtd = String(i.quantidade || 0).padEnd(4, ' ');
    const vUnit = (i.valor_unitario || '').padEnd(10, ' ');
    const vTot = (i.valor_total || '').padEnd(10, ' ');
    tabela_itens += `| ${String(i.item).padEnd(4, ' ')} | ${desc} | ${catmat} | ${unid} | ${qtd} | ${vUnit} | ${vTot} |\n`;
  });
} else {
  tabela_itens += '| -    | -                                          | -        | -    | -    | -          | -          |\n';
}

// Gerar o texto formatado único para exibição na tela seguindo AGU
const texto_formatado = `1. DO OBJETO\n1.1. O objeto da contratação é a ${variables.objeto_contratacao || '...'}, conforme especificações e quantidades estabelecidas neste Termo de Referência.\n\n1.2. A tabela abaixo resume os itens que compõem o objeto:\n${tabela_itens}\n2. FUNDAMENTAÇÃO DA CONTRATAÇÃO\n2.1. A fundamentação da contratação e de seus quantitativos encontra-se detalhada no Estudo Técnico Preliminar (ETP) nº ${variables.numero_processo || '...'}, que constitui anexo deste Termo de Referência, nos termos do art. 18, § 1º, da Lei nº 14.133, de 2021.\n2.2. A justificativa para a contratação é:\n${variables.justificativa_etp || '...'}\n\n3. DESCRIÇÃO DA SOLUÇÃO COMO UM TODO\n3.1. A solução como um todo compreende:\n${variables.descricao_solucao_etp || '...'}`;

return [{ json: { sucesso: true, bloco: 1, texto_formatado, variables: { ...variables, itens } } }];
